        rio_re[m*ms+2*ios] = x0_re; rio_im[m*ms+2*ios] = x0_im;
        rio_re[m*ms+6*ios] = x1_re; rio_im[m*ms+6*ios] = x1_im;
        rio_re[m*ms+10*ios] = x2_re; rio_im[m*ms+10*ios] = x2_im;
        rio_re[m*ms+14*ios] = x3_re; rio_im[m*ms+14*ios] = x3_im;

